/// OPEN EXTEND TST-FILE7
fn tst_file7_open_extend(state: &mut ProgramState) {
    let path = std::env::var("TST_FILE7").unwrap_or("tst_file7.dat".to_string());
    match CobolFile::open_extend(&path) {
        Ok(handle) => { state._fh_tst_file7 = handle; state._fs_tst_file7 = FileStatus::Success; }
        Err(_) => { state._fs_tst_file7 = FileStatus::Error("35".to_string()); }
    }
}

/// READ TST-FILE7
fn tst_file7_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_tst_file7.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(4);
            if _len > 0 { let _end = _len.min(0+4); state.tst7_rec = String::from_utf8_lossy(&_bytes[0.._end]).to_string().cobol_into(); }
            state._fs_tst_file7 = FileStatus::Success;
        }
        Err(FileStatus::AtEnd) => {
            state._fs_tst_file7 = FileStatus::AtEnd;
        }
        Err(e) => {
            state._fs_tst_file7 = e.clone();
        }
    }
    Ok(())
}

/// WRITE to TST-FILE7
fn tst_file7_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 4];
    { let _src = state.tst7_rec.as_bytes(); let _end = (0+4).min(_buf.len()); let _cl = _src.len().min(_end-0); _buf[0..0+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_tst_file7.write_record(&_buf) {
        Ok(()) => state._fs_tst_file7 = FileStatus::Success,
        Err(e) => state._fs_tst_file7 = e,
    }
}

/// CLOSE TST-FILE7
fn tst_file7_close(state: &mut ProgramState) {
    match state._fh_tst_file7.close() {
        Ok(()) => state._fs_tst_file7 = FileStatus::Success,
        Err(e) => state._fs_tst_file7 = e,
    }
}

/// Paragraph: _IMPLICIT_
fn p__implicit_(state: &mut ProgramState) {
    tst_file1_open_input(state);
    tst_file1_close(state);
    tst_file2_open_input(state);
    tst_file2_close(state);
    tst_file3_open_input(state);
    tst_file3_close(state);
    tst_file4_open_input(state);
    tst_file4_close(state);
    tst_file5_open_input(state);
    tst_file5_close(state);
    tst_file6_open_input(state);
    tst_file6_close(state);
    tst_file7_open_input(state);
    tst_file7_close(state);
    std::process::exit(0);
}

fn main() {
    let mut state = ProgramState::default();
    p__implicit_(&mut state);
}
